52: HeaderUtility::GetAllOfHeaderAsStringResult
53: HeaderUtility::getAllOfHeaderAsString(const HeaderMap::GetResult& header_value,
54:                                       absl::string_view separator) {
55:   GetAllOfHeaderAsStringResult result;
56:   // In this case we concatenate all found headers using a delimiter before performing the
57:   // final match. We use an InlinedVector of absl::string_view to invoke the optimized join
58:   // algorithm. This requires a copying phase before we invoke join. The 3 used as the inline
59:   // size has been arbitrarily chosen.
60:   // TODO(mattklein123): Do we need to normalize any whitespace here?
61:   absl::InlinedVector<absl::string_view, 3> string_view_vector;
62:   string_view_vector.reserve(header_value.size());
63:   for (size_t i = 0; i < header_value.size(); i++) {
64:     string_view_vector.push_back(header_value[i]->value().getStringView());
65:   }
66:   result.result_backing_string_ = absl::StrJoin(string_view_vector, separator);
67: 
68:   return result;
69: }
