132: bool HeaderUtility::headerNameIsValid(absl::string_view header_key) {
133:   if (!header_key.empty() && header_key[0] == ':') {
134:     header_key.remove_prefix(1);
135:     if (header_key.empty()) {
136:       return false;
137:     }
138:   }
139:   // For all other header use HTTP/1 semantics. The only difference from HTTP/2 is that
140:   // uppercase characters are allowed. This allows HTTP filters to add header with mixed
141:   // case names. The HTTP/1 codec will send as is, as uppercase characters are allowed.
142:   // However the HTTP/2 codec will NOT convert these to lowercase when serializing the
143:   // header map, thus producing an invalid request.
144:   // TODO(yanavlasov): make validation in HTTP/2 case stricter.
145:   bool is_valid = true;
146:   for (auto iter = header_key.begin(); iter != header_key.end() && is_valid; ++iter) {
147:     is_valid &= testCharInTable(kGenericHeaderNameCharTable, *iter);
148:   }
149:   return is_valid;
150: }
